(function () {
  const VERSION = 4;
  const SIZE = 33;
  const DATA_CODEWORDS = 80;
  const EC_CODEWORDS = 20;

  const EXP = new Array(512);
  const LOG = new Array(256);
  let value = 1;
  for (let i = 0; i < 255; i += 1) {
    EXP[i] = value;
    LOG[value] = i;
    value <<= 1;
    if (value & 0x100) value ^= 0x11d;
  }
  for (let i = 255; i < 512; i += 1) EXP[i] = EXP[i - 255];

  function mul(a, b) {
    if (a === 0 || b === 0) return 0;
    return EXP[LOG[a] + LOG[b]];
  }

  function generatorPoly(degree) {
    let poly = [1];
    for (let i = 0; i < degree; i += 1) {
      const next = new Array(poly.length + 1).fill(0);
      for (let j = 0; j < poly.length; j += 1) {
        next[j] ^= poly[j];
        next[j + 1] ^= mul(poly[j], EXP[i]);
      }
      poly = next;
    }
    return poly;
  }

  function reedSolomon(data) {
    const gen = generatorPoly(EC_CODEWORDS);
    const rem = new Array(EC_CODEWORDS).fill(0);
    for (const byte of data) {
      const factor = byte ^ rem.shift();
      rem.push(0);
      for (let i = 0; i < EC_CODEWORDS; i += 1) {
        rem[i] ^= mul(gen[i + 1], factor);
      }
    }
    return rem;
  }

  function appendBits(bits, valueToAppend, length) {
    for (let i = length - 1; i >= 0; i -= 1) {
      bits.push((valueToAppend >>> i) & 1);
    }
  }

  function makeCodewords(text) {
    const bytes = Array.from(new TextEncoder().encode(text));
    if (bytes.length > 78) {
      throw new Error("QR link is too long for the local compact encoder.");
    }
    const bits = [];
    appendBits(bits, 0x4, 4);
    appendBits(bits, bytes.length, 8);
    for (const byte of bytes) appendBits(bits, byte, 8);
    const maxBits = DATA_CODEWORDS * 8;
    appendBits(bits, 0, Math.min(4, maxBits - bits.length));
    while (bits.length % 8 !== 0) bits.push(0);
    const data = [];
    for (let i = 0; i < bits.length; i += 8) {
      data.push(bits.slice(i, i + 8).reduce((sum, bit) => (sum << 1) | bit, 0));
    }
    for (let pad = 0xec; data.length < DATA_CODEWORDS; pad ^= 0xfd) {
      data.push(pad);
    }
    return data.concat(reedSolomon(data));
  }

  function blankMatrix() {
    return {
      modules: Array.from({ length: SIZE }, () => new Array(SIZE).fill(false)),
      reserved: Array.from({ length: SIZE }, () => new Array(SIZE).fill(false)),
    };
  }

  function setCell(qr, x, y, dark, reserve = true) {
    if (x < 0 || y < 0 || x >= SIZE || y >= SIZE) return;
    qr.modules[y][x] = Boolean(dark);
    if (reserve) qr.reserved[y][x] = true;
  }

  function addFinder(qr, x, y) {
    for (let dy = -1; dy <= 7; dy += 1) {
      for (let dx = -1; dx <= 7; dx += 1) {
        const xx = x + dx;
        const yy = y + dy;
        const inOuter = dx >= 0 && dx <= 6 && dy >= 0 && dy <= 6;
        const inInner = dx >= 2 && dx <= 4 && dy >= 2 && dy <= 4;
        const dark = inOuter && (dx === 0 || dx === 6 || dy === 0 || dy === 6 || inInner);
        setCell(qr, xx, yy, dark);
      }
    }
  }

  function addAlignment(qr, cx, cy) {
    for (let dy = -2; dy <= 2; dy += 1) {
      for (let dx = -2; dx <= 2; dx += 1) {
        const dark = Math.max(Math.abs(dx), Math.abs(dy)) !== 1;
        setCell(qr, cx + dx, cy + dy, dark);
      }
    }
  }

  function addPatterns(qr) {
    addFinder(qr, 0, 0);
    addFinder(qr, SIZE - 7, 0);
    addFinder(qr, 0, SIZE - 7);
    for (let i = 8; i < SIZE - 8; i += 1) {
      setCell(qr, i, 6, i % 2 === 0);
      setCell(qr, 6, i, i % 2 === 0);
    }
    addAlignment(qr, 26, 26);
    setCell(qr, 8, SIZE - 8, true);
    for (let i = 0; i < 9; i += 1) {
      if (i !== 6) {
        setCell(qr, 8, i, false);
        setCell(qr, i, 8, false);
      }
    }
    for (let i = SIZE - 8; i < SIZE; i += 1) setCell(qr, 8, i, false);
    for (let i = SIZE - 7; i < SIZE; i += 1) setCell(qr, i, 8, false);
  }

  function maskBit(x, y) {
    return (x + y) % 2 === 0;
  }

  function addData(qr, codewords) {
    const bits = [];
    for (const byte of codewords) appendBits(bits, byte, 8);
    let bitIndex = 0;
    let upward = true;
    for (let right = SIZE - 1; right >= 1; right -= 2) {
      if (right === 6) right -= 1;
      for (let step = 0; step < SIZE; step += 1) {
        const y = upward ? SIZE - 1 - step : step;
        for (let col = 0; col < 2; col += 1) {
          const x = right - col;
          if (qr.reserved[y][x]) continue;
          const raw = bitIndex < bits.length ? bits[bitIndex] === 1 : false;
          setCell(qr, x, y, raw !== maskBit(x, y), false);
          bitIndex += 1;
        }
      }
      upward = !upward;
    }
  }

  function bchFormat(data) {
    let bits = data << 10;
    const gen = 0x537;
    for (let i = 14; i >= 10; i -= 1) {
      if ((bits >>> i) & 1) bits ^= gen << (i - 10);
    }
    return ((data << 10) | bits) ^ 0x5412;
  }

  function addFormat(qr) {
    const format = bchFormat(0x08);
    const positionsA = [
      [8, 0], [8, 1], [8, 2], [8, 3], [8, 4], [8, 5], [8, 7], [8, 8],
      [7, 8], [5, 8], [4, 8], [3, 8], [2, 8], [1, 8], [0, 8],
    ];
    const positionsB = [
      [SIZE - 1, 8], [SIZE - 2, 8], [SIZE - 3, 8], [SIZE - 4, 8],
      [SIZE - 5, 8], [SIZE - 6, 8], [SIZE - 7, 8], [SIZE - 8, 8],
      [8, SIZE - 7], [8, SIZE - 6], [8, SIZE - 5], [8, SIZE - 4],
      [8, SIZE - 3], [8, SIZE - 2], [8, SIZE - 1],
    ];
    for (let i = 0; i < 15; i += 1) {
      const dark = ((format >>> i) & 1) === 1;
      setCell(qr, positionsA[i][0], positionsA[i][1], dark);
      setCell(qr, positionsB[i][0], positionsB[i][1], dark);
    }
  }

  function draw(canvas, text, options = {}) {
    const scale = options.scale || 6;
    const quiet = 4;
    const qr = blankMatrix();
    addPatterns(qr);
    addData(qr, makeCodewords(text));
    addFormat(qr);
    const pixelSize = (SIZE + quiet * 2) * scale;
    canvas.width = pixelSize;
    canvas.height = pixelSize;
    const ctx = canvas.getContext("2d");
    ctx.imageSmoothingEnabled = false;
    ctx.fillStyle = options.light || "#ffffff";
    ctx.fillRect(0, 0, pixelSize, pixelSize);
    ctx.fillStyle = options.dark || "#000000";
    for (let y = 0; y < SIZE; y += 1) {
      for (let x = 0; x < SIZE; x += 1) {
        if (qr.modules[y][x]) {
          ctx.fillRect((x + quiet) * scale, (y + quiet) * scale, scale, scale);
        }
      }
    }
  }

  window.VaralicaQRCode = { draw };
})();
